// frontend/src/pages/Dashboard.js
import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import PlaceCard from '../components/PlaceCard';
import CheckoutModal from '../components/CheckoutModal';
import Toast from '../components/Toast';
import {
  getPlaces, getPrediction, checkIn, checkOut,
  getMyActiveCheckin, getMyHistory,
} from '../services/api';

const CATEGORIES = ['all', 'mall', 'cafe', 'gym', 'restaurant'];

export default function Dashboard() {
  const { user, logout } = useAuth();

  const [places, setPlaces]         = useState([]);
  const [predictions, setPred]      = useState({});
  const [category, setCategory]     = useState('all');
  const [search, setSearch]         = useState('');
  const [activeCheckin, setActiveCI] = useState(null); // { id, place_id, place_name }
  const [history, setHistory]       = useState([]);
  const [showHistory, setShowHist]  = useState(false);
  const [modal, setModal]           = useState(null);   // { place_id, place_name }
  const [toast, setToast]           = useState(null);
  const [locating, setLocating]     = useState(false);
  const [locMsg, setLocMsg]         = useState('');
  const [loading, setLoading]       = useState(true);
  const [tab, setTab]               = useState('explore'); // 'explore' | 'history'

  const showToast = (message, type = 'success') => setToast({ message, type });

  // Load places + predictions
  const loadPlaces = useCallback(async (cat = category, q = search) => {
    setLoading(true);
    try {
      const data = await getPlaces(cat, q);
      setPlaces(data);
      // Load predictions for each place (parallel)
      const predEntries = await Promise.all(
        data.map(p => getPrediction(p.id).then(pred => [p.id, pred]))
      );
      setPred(Object.fromEntries(predEntries));
    } catch (e) {
      showToast('Places load nahi hue. Backend chalu karo.', 'error');
    } finally {
      setLoading(false);
    }
  }, []);

  // Load active check-in
  const loadActiveCheckin = useCallback(async () => {
    try {
      const ci = await getMyActiveCheckin();
      setActiveCI(ci);
    } catch {
      setActiveCI(null);
    }
  }, []);

  useEffect(() => {
    loadPlaces('all', '');
    loadActiveCheckin();
  }, []);

  // Search & filter
  useEffect(() => {
    const t = setTimeout(() => loadPlaces(category, search), 400);
    return () => clearTimeout(t);
  }, [search, category]);

  // History load
  useEffect(() => {
    if (tab === 'history') {
      getMyHistory().then(setHistory).catch(() => setHistory([]));
    }
  }, [tab]);

  // Detect location
  const detectLocation = () => {
    if (!navigator.geolocation) {
      showToast('Aapka browser location support nahi karta', 'error');
      return;
    }
    setLocating(true);
    setLocMsg('Location detect ho rahi hai...');
    navigator.geolocation.getCurrentPosition(
      pos => {
        setLocMsg(`📍 ${pos.coords.latitude.toFixed(4)}, ${pos.coords.longitude.toFixed(4)}`);
        setLocating(false);
        showToast('Location mil gayi!');
      },
      () => {
        setLocMsg('Location nahi mili. Permission do browser mein.');
        setLocating(false);
        showToast('Location access deny ho gayi', 'error');
      }
    );
  };

  // Check-in handler
  const handleCheckin = async (place_id) => {
    try {
      const res = await checkIn(place_id);
      showToast(res.message);
      await loadActiveCheckin();
    } catch (err) {
      showToast(err.response?.data?.error || 'Check-in nahi hua', 'error');
    }
  };

  // Checkout - show modal first
  const handleCheckout = (place_id) => {
    const place = places.find(p => p.id === place_id);
    setModal({ place_id, place_name: place?.name || 'Yahan' });
  };

  // Submit cost from modal
  const handleCostSubmit = async (amount) => {
    try {
      const res = await checkOut(modal.place_id, amount);
      showToast(res.message);
      setModal(null);
      await loadActiveCheckin();
      await loadPlaces(category, search); // Refresh avg_cost
    } catch (err) {
      showToast(err.response?.data?.error || 'Checkout nahi hua', 'error');
      setModal(null);
    }
  };

  const s = {
    page:   { minHeight: '100vh', background: '#f7f8fc' },
    nav: {
      background: '#fff', padding: '0 20px',
      borderBottom: '1px solid #eee', position: 'sticky',
      top: 0, zIndex: 100,
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      height: '60px',
    },
    logo:   { fontSize: '20px', fontWeight: '700', color: '#1a1a2e' },
    logoG:  { color: '#1D9E75' },
    navRight: { display: 'flex', alignItems: 'center', gap: '12px' },
    userBadge: {
      background: '#e8f8f2', color: '#0f6e56', padding: '6px 12px',
      borderRadius: '20px', fontSize: '13px', fontWeight: '500',
    },
    logoutBtn: {
      background: 'none', border: '1px solid #ddd', color: '#888',
      padding: '6px 12px', borderRadius: '8px', fontSize: '13px', cursor: 'pointer',
    },
    main:   { maxWidth: '1100px', margin: '0 auto', padding: '24px 16px' },
    tabRow: {
      display: 'flex', gap: '8px', marginBottom: '20px',
      borderBottom: '2px solid #eee', paddingBottom: '0',
    },
    tabBtn: (active) => ({
      padding: '10px 18px', border: 'none', background: 'none',
      fontSize: '14px', fontWeight: '600', cursor: 'pointer',
      color: active ? '#1D9E75' : '#aaa',
      borderBottom: active ? '2px solid #1D9E75' : '2px solid transparent',
      marginBottom: '-2px', transition: 'all .2s',
    }),
    searchRow: {
      display: 'flex', gap: '10px', marginBottom: '16px', flexWrap: 'wrap',
    },
    searchInput: {
      flex: 1, minWidth: '200px', padding: '12px 16px',
      border: '1.5px solid #e8e8e8', borderRadius: '12px',
      fontSize: '14px', outline: 'none', background: '#fff',
    },
    locBtn: {
      padding: '12px 18px', background: '#1D9E75', color: '#fff',
      border: 'none', borderRadius: '12px', fontSize: '13px',
      fontWeight: '600', cursor: 'pointer', whiteSpace: 'nowrap',
      display: 'flex', alignItems: 'center', gap: '6px',
    },
    locMsg: { fontSize: '12px', color: '#888', marginBottom: '16px', minHeight: '18px' },
    cats: { display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' },
    catBtn: (active) => ({
      padding: '7px 16px', border: '1.5px solid ' + (active ? '#1D9E75' : '#e8e8e8'),
      borderRadius: '20px', background: active ? '#e8f8f2' : '#fff',
      color: active ? '#0f6e56' : '#888', fontSize: '13px',
      fontWeight: '500', cursor: 'pointer', transition: 'all .2s',
    }),
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '14px',
    },
    empty: {
      textAlign: 'center', padding: '60px 20px', color: '#bbb',
    },
    historyCard: {
      background: '#fff', borderRadius: '12px', padding: '14px 16px',
      marginBottom: '10px', border: '1px solid #f0f0f0',
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    },
    histLeft: {},
    histName: { fontWeight: '600', fontSize: '14px', color: '#1a1a2e' },
    histSub:  { fontSize: '12px', color: '#aaa', marginTop: '2px' },
    histCost: { fontWeight: '700', color: '#1D9E75', fontSize: '16px' },
  };

  const catLabels = { all: 'Sab', mall: 'Malls', cafe: 'Cafes', gym: 'Gyms', restaurant: 'Restaurants' };

  return (
    <div style={s.page}>
      {/* Navbar */}
      <nav style={s.nav}>
        <div style={s.logo}>Visit<span style={s.logoG}>Wise</span> AI</div>
        <div style={s.navRight}>
          <span style={s.userBadge}>👋 {user?.name?.split(' ')[0]}</span>
          <button style={s.logoutBtn} onClick={logout}>Logout</button>
        </div>
      </nav>

      <div style={s.main}>
        {/* Tabs */}
        <div style={s.tabRow}>
          <button style={s.tabBtn(tab === 'explore')} onClick={() => setTab('explore')}>🔍 Explore</button>
          <button style={s.tabBtn(tab === 'history')} onClick={() => setTab('history')}>📋 Meri History</button>
        </div>

        {/* ── EXPLORE TAB ── */}
        {tab === 'explore' && (
          <>
            {/* Search + Location */}
            <div style={s.searchRow}>
              <input
                style={s.searchInput}
                placeholder="🔍 Mall, cafe, gym dhundo..."
                value={search}
                onChange={e => setSearch(e.target.value)}
              />
              <button style={s.locBtn} onClick={detectLocation} disabled={locating}>
                {locating ? '⏳' : '📍'} {locating ? 'Detecting...' : 'Mere Paas'}
              </button>
            </div>
            {locMsg && <div style={s.locMsg}>{locMsg}</div>}

            {/* Category filters */}
            <div style={s.cats}>
              {CATEGORIES.map(c => (
                <button
                  key={c}
                  style={s.catBtn(category === c)}
                  onClick={() => setCategory(c)}
                >{catLabels[c] || c}</button>
              ))}
            </div>

            {/* Active check-in banner */}
            {activeCheckin && (
              <div style={{
                background: '#e8f8f2', border: '1.5px solid #1D9E75', borderRadius: '12px',
                padding: '12px 16px', marginBottom: '16px',
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              }}>
                <span style={{ fontSize: '14px', color: '#0f6e56' }}>
                  ✅ Aap abhi <strong>{activeCheckin.place_name}</strong> mein hain
                </span>
                <button
                  onClick={() => handleCheckout(activeCheckin.place_id)}
                  style={{
                    padding: '7px 14px', background: '#c0392b', color: '#fff',
                    border: 'none', borderRadius: '8px', fontSize: '13px', cursor: 'pointer',
                  }}
                >Checkout</button>
              </div>
            )}

            {/* Places grid */}
            {loading ? (
              <div style={s.empty}>⏳ Places load ho rahe hain...</div>
            ) : places.length === 0 ? (
              <div style={s.empty}>
                <div style={{ fontSize: '40px', marginBottom: '12px' }}>🔍</div>
                <div>Koi place nahi mila</div>
                <div style={{ fontSize: '13px', marginTop: '6px' }}>Search ya filter change karo</div>
              </div>
            ) : (
              <div style={s.grid}>
                {places.map(place => (
                  <PlaceCard
                    key={place.id}
                    place={place}
                    prediction={predictions[place.id]}
                    isCheckedIn={activeCheckin?.place_id === place.id}
                    onCheckin={handleCheckin}
                    onCheckout={handleCheckout}
                  />
                ))}
              </div>
            )}
          </>
        )}

        {/* ── HISTORY TAB ── */}
        {tab === 'history' && (
          <div>
            <h2 style={{ fontSize: '16px', fontWeight: '600', color: '#1a1a2e', marginBottom: '16px' }}>
              Aapki Check-in History
            </h2>
            {history.length === 0 ? (
              <div style={s.empty}>
                <div style={{ fontSize: '40px', marginBottom: '12px' }}>📋</div>
                <div>Abhi tak koi check-in nahi hua</div>
              </div>
            ) : (
              history.map(h => (
                <div key={h.id} style={s.historyCard}>
                  <div style={s.histLeft}>
                    <div style={s.histName}>{h.place_name}</div>
                    <div style={s.histSub}>
                      {h.category} · {new Date(h.checked_in_at).toLocaleDateString('hi-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                    </div>
                  </div>
                  <div style={s.histCost}>
                    {h.amount_spent ? `₹${Math.round(h.amount_spent)}` : '—'}
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </div>

      {/* Checkout Modal */}
      {modal && (
        <CheckoutModal
          placeName={modal.place_name}
          onSubmit={handleCostSubmit}
          onClose={() => setModal(null)}
        />
      )}

      {/* Toast */}
      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  );
}
